const aermini_FileDownloader_picture = "data:image/png;base64,";
const aermini_FileDownloader_icon = "data:image/svg+xml;base64,";
const aermini_FileDownloader_extensionId = "AerFileDownloader";

/** @typedef {string|number|boolean} SCarg */

class AerFileDownloader {
    constructor(runtime) {
        this.runtime = runtime;
        this._formatMessage = runtime.getFormatMessage({
            "zh-cn": {
                "AerFileDownloader.name": "AerMini的文件下载",
                "AerFileDownloader.downloadURL": "从url[url]下载文件 命名为[filename]",
                "AerFileDownloader.downloadCONTENT": "将[content]命名为[filename]并下载",
            },
            en: {
                "AerFileDownloader.name": "AerMini's file download",
                "AerFileDownloader.downloadURL": "Download a file from url [url] and name it [filename]",
                "AerFileDownloader.downloadCONTENT": "Download content [content] and name it [filename]",
            }
        })
    }

    /**
     * @param {string} id
     * @return {string}
     */
    formatMessage(id) {
        return this._formatMessage({
            id,
            default: id,
            description: id
        });
    }
    

    getInfo() {
        return {
            id: aermini_FileDownloader_extensionId,
            name: this.formatMessage("AerFileDownloader.name"),
            blockIconURI: aermini_FileDownloader_icon,
            menuIconURI: aermini_FileDownloader_icon,
            color1: "#9B30FF",
            color2: "#AB82FF",
            blocks: [
                {
                    opcode: "downloadURL",
                    blockType: "command",
                    text: this.formatMessage("AerFileDownloader.downloadURL"),
                    disableMonitor: true,
                    arguments: {
                    	url: { type: "string", defaultValue: "https://example.com" },
                        filename: { type: "string", defaultValue: "file.txt" },
                    },
                },
                {
                    opcode: "downloadCONTENT",
                    blockType: "command",
                    text: this.formatMessage("AerFileDownloader.downloadCONTENT"),
                    disableMonitor: true,
                    arguments: {
                    	content: { type: "string", defaultValue: "你好" },
                        filename: { type: "string", defaultValue: "file.txt" },
                    },
                },
            ],
            menus: {
			},
        };
    }

    downloadURL(args) {
        async function downloadFile(urlOrContent, fileName, isUrl = true) {
            if (isUrl) {
                try {
                    const response = await fetch(urlOrContent);
                    const blob = await response.blob();
                    const url = URL.createObjectURL(blob);
                    const link = document.createElement('a');
                    link.href = url;
                    link.download = fileName;
                    link.click();
                    URL.revokeObjectURL(url);
                } catch (error) {
                    console.error('下载文件时出错:', error);
                }
            } else {
                const blob = new Blob([urlOrContent], { type: 'text/plain' });
                const url = URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = fileName;
                link.click();
                URL.revokeObjectURL(url);
            }
        }

        downloadFile(args.url, args.filename);
    }

    downloadCONTENT(args) {
        async function downloadFile(urlOrContent, fileName, isUrl = true) {
            if (isUrl) {
                try {
                    const response = await fetch(urlOrContent);
                    const blob = await response.blob();
                    const url = URL.createObjectURL(blob);
                    const link = document.createElement('a');
                    link.href = url;
                    link.download = fileName;
                    link.click();
                    URL.revokeObjectURL(url);
                } catch (error) {
                    console.error('下载文件时出错:', error);
                }
            } else {
                const blob = new Blob([urlOrContent], { type: 'text/plain' });
                const url = URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = fileName;
                link.click();
                URL.revokeObjectURL(url);
            }
        }

        downloadFile(args.content, args.filename, false);    

    }
    
    
}

window.tempExt = {
    Extension: AerFileDownloader,
    info: {
        name: "AerFileDownloader.name",
        description: "AerFileDownloader.descp",
        extensionId: aermini_FileDownloader_extensionId,
        iconURL: aermini_FileDownloader_picture,
        insetIconURL: aermini_FileDownloader_icon,
        featured: true,
        disabled: false,
        collaboratorList: [
            {
              collaborator: "AerMini @ CCW",
              collaboratorURL: "https://www.ccw.site/student/639be395cf406d52eac0f388",
            },
        ]
    },
    l10n: {
        "zh-cn": {
            "AerFileDownloader.name": "AerMini的文件下载",
            "AerFileDownloader.descp": "从任何角落下载内容 ~"
        },
        en: {
            "AerFileDownloader.name": "AerMini's file download",
            "AerFileDownloader.descp": "Download content from any corner ~"
        }
    }
};
